import{_ as t,o as i,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const v=JSON.parse('{"title":"Investigating Branch Deepviews Optimization","description":"","frontmatter":{"title":"Investigating Branch Deepviews Optimization","slug":"investigating-branch-deepviews-optimizations"},"headers":[],"relativePath":"account-hub/investigating-branch-deepviews-optimizations.md","filePath":"account-hub/investigating-branch-deepviews-optimizations.md"}'),s={name:"account-hub/investigating-branch-deepviews-optimizations.md"};function o(r,e,h,p,l,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<p>The Branch team conducted new tests to see how we can improve the click-to-install (CTI) rates of Branch Deepviews 🔍</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Our product and engineering teams are always looking out for any optimizations that can be made to improve the services Branch provides. This time, we set our eyes on improving CTI rates when a Branch <a href="./deepviews.html">Deepview</a> is involved. The hypothesis was that better Deepviews would lead to more conversions.</p><h2 id="testing-results" tabindex="-1">Testing &amp; Results <a class="header-anchor" href="#testing-results" aria-label="Permalink to &quot;Testing &amp; Results&quot;">​</a></h2><p>We tested <strong>Five Andoird &amp; iOS apps</strong> where we showed different Deepview variants from a sharing link. From there, we measured the differences between treatment and control when looking at CTI.</p><p>From the investigation, we found the following results:</p><ol><li>Almost all variants performed better than the baseline behavior (some as high as +29% CTI)</li><li>Deepview designs influence user behavior</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>The Branch team is moving forward with continued experimentation on this use case to make the user experience better for the end user and increase conversion rates. For now, no new features are available.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ready to learn more about Branch Deepviews? View our guide here: <a href="./deepviews.html">Deepview</a></p></div>',10)])])}const m=t(s,[["render",o]]);export{v as __pageData,m as default};
